randomNumber:
with Ada.Text_IO;
with Ada.Numerics.Float_Random;
with Ada.Numerics.Discrete_Random;
with Ada.Calendar;

procedure Random_Number_Demo is
   -- For floating-point numbers
   package Float_Rand is new Ada.Numerics.Float_Random;
   Gen_Float : Float_Rand.Generator;

   -- For a specific integer range
   subtype Integer_Range is Integer range 1 .. 100;
   package Int_Rand is new Ada.Numerics.Discrete_Random (Integer_Range);
   Gen_Int : Int_Rand.Generator;

begin
   -- Seed the generators using the current time for non-repeatable sequences
   Float_Rand.Reset (Gen_Float, Ada.Calendar.Clock);
   Int_Rand.Reset (Gen_Int, Ada.Calendar.Clock);

   -- Generate a random float between 0.0 and 1.0
   declare
      Random_Float : Float := Float_Rand.Random (Gen_Float);
   begin
      Ada.Text_IO.Put_Line ("Random Float [0.0, 1.0): " & Float'Image (Random_Float));
   end;

   -- Generate a random integer within the defined subtype range
   declare
      Random_Int : Integer_Range := Int_Rand.Random (Gen_Int);
   begin
      Ada.Text_IO.Put_Line ("Random Integer [1-100]: " & Integer'Image (Random_Int));
   end;
end Random_Number_Demo;

reverseString:
with Ada.Text_IO;

function Reverse_String (Input : String) return String is
   Reversed : String (Input'Range) := (others => ' '); -- Initialize with same bounds
begin
   if Input'Length <= 1 then
      return Input;
   end if;

   for I in Input'Range loop
      -- Calculate corresponding position from the end
      Reversed (I) := Input (Input'Last - (I - Input'First));
   end loop;
   return Reversed;
end Reverse_String;

-- Example Usage
procedure Reverse_String_Demo is
   Original : String := "Hello, Ada!";
   Reversed : String := Reverse_String (Original);
begin
   Ada.Text_IO.Put_Line ("Original: " & Original);
   Ada.Text_IO.Put_Line ("Reversed: " & Reversed);
end Reverse_String_Demo;

fibonacci:
with Ada.Text_IO;

function Fibonacci (N : Natural) return Long_Long_Integer is
   -- Using Long_Long_Integer to handle larger results.
   -- For arbitrary size, use Ada.Numerics.Big_Numbers.
   A : Long_Long_Integer := 0;
   B : Long_Long_Integer := 1;
   Next_Val : Long_Long_Integer;
begin
   if N = 0 then
      return A;
   elsif N = 1 then
      return B;
   end if;

   for I in 2 .. N loop
      Next_Val := A + B;
      A := B;
      B := Next_Val;
   end loop;

   return B;
end Fibonacci;

-- Example Usage
procedure Fibonacci_Demo is
   Result : Long_Long_Integer;
begin
   Ada.Text_IO.Put_Line ("Fibonacci sequence:");
   for I in 0 .. 15 loop
      Result := Fibonacci (I);
      Ada.Text_IO.Put (Long_Long_Integer'Image (Result));
   end loop;
   Ada.Text_IO.New_Line;
   Ada.Text_IO.Put_Line ("F(93) is near the limit for Long_Long_Integer:");
   Ada.Text_IO.Put_Line (Long_Long_Integer'Image(Fibonacci(93)));
end Fibonacci_Demo;

factorial:
with Ada.Text_IO;

function Factorial (N : Natural) return Long_Long_Integer is
   -- Using Long_Long_Integer. Overflows after 20!
   -- For arbitrary size, use Ada.Numerics.Big_Numbers.
   Result : Long_Long_Integer := 1;
begin
   if N > 1 then
      for I in 2 .. N loop
         Result := Result * Long_Long_Integer (I);
      end loop;
   end if;
   return Result;
end Factorial;

-- Example Usage
procedure Factorial_Demo is
begin
   Ada.Text_IO.Put_Line ("Factorial of 5 is" & Factorial (5)'Image);
   Ada.Text_IO.Put_Line ("Factorial of 0 is" & Factorial (0)'Image);
   Ada.Text_IO.Put_Line ("Factorial of 20 is" & Factorial (20)'Image);
end Factorial_Demo;

primeCheck:
with Ada.Text_IO;
with Ada.Numerics.Elementary_Functions;

function Is_Prime (N : Long_Integer) return Boolean is
   use Ada.Numerics.Elementary_Functions;
   Limit : Long_Integer;
begin
   if N <= 1 then
      return False;
   end if;
   if N <= 3 then
      return True;
   end if;
   if N mod 2 = 0 or N mod 3 = 0 then
      return False;
   end if;

   Limit := Long_Integer (Sqrt (Float (N)));
   declare
      I : Long_Integer := 5;
   begin
      while I <= Limit loop
         if N mod I = 0 or N mod (I + 2) = 0 then
            return False;
         end if;
         I := I + 6;
      end loop;
   end;

   return True;
end Is_Prime;

-- Example Usage
procedure Prime_Check_Demo is
   Numbers_To_Check : constant array (1 .. 10) of Long_Integer := (2, 3, 4, 17, 25, 29, 97, 100, 1, 104_729);
begin
   for Num of Numbers_To_Check loop
      if Is_Prime (Num) then
         Ada.Text_IO.Put_Line (Num'Image & " is prime.");
      else
         Ada.Text_IO.Put_Line (Num'Image & " is not prime.");
      end if;
   end loop;
end Prime_Check_Demo;

readFile:
with Ada.Text_IO;

procedure Read_File_Demo is
   File_Handle : Ada.Text_IO.File_Type;
   Filename    : constant String := "ada_read_test.txt";
begin
   -- Create a dummy file for reading
   begin
      Ada.Text_IO.Create (File => File_Handle, Name => Filename);
      Ada.Text_IO.Put_Line (File_Handle, "First line from Ada.");
      Ada.Text_IO.Put_Line (File_Handle, "Second line of text.");
      Ada.Text_IO.Close (File_Handle);
      Ada.Text_IO.Put_Line ("Created dummy file: " & Filename);
   exception
      when Ada.Text_IO.Name_Error =>
         Ada.Text_IO.Put_Line ("Error creating file.");
         return;
   end;

   Ada.Text_IO.New_Line;
   Ada.Text_IO.Put_Line ("--- Reading file " & Filename & " ---");

   -- Open the file for reading and process it
   begin
      Ada.Text_IO.Open (File => File_Handle, Mode => Ada.Text_IO.In_File, Name => Filename);

      while not Ada.Text_IO.End_Of_File (File_Handle) loop
         Ada.Text_IO.Put_Line (Ada.Text_IO.Get_Line (File_Handle));
      end loop;

      Ada.Text_IO.Close (File_Handle);
   exception
      when Ada.Text_IO.Name_Error =>
         Ada.Text_IO.Put_Line ("File not found: " & Filename);
   end;
end Read_File_Demo;

writeFile:
with Ada.Text_IO;

procedure Write_File_Demo is
   File_Handle : Ada.Text_IO.File_Type;
   Filename    : constant String := "output_ada.txt";
begin
   -- 1. Overwrite or Create a new file
   Ada.Text_IO.Put_Line ("--- Writing (Overwrite) to " & Filename & " ---");
   begin
      Ada.Text_IO.Create (File => File_Handle, Mode => Ada.Text_IO.Out_File, Name => Filename);
      Ada.Text_IO.Put_Line (File_Handle, "This line overwrites existing content.");
      Ada.Text_IO.Put_Line (File_Handle, "Written by an Ada program.");
      Ada.Text_IO.Close (File_Handle);
      Ada.Text_IO.Put_Line ("Content written successfully.");
   exception
      when Ada.Text_IO.Name_Error | Ada.Text_IO.Use_Error =>
         Ada.Text_IO.Put_Line ("Error: Could not write to file.");
   end;

   -- 2. Append to an existing file
   Ada.Text_IO.New_Line;
   Ada.Text_IO.Put_Line ("--- Appending to " & Filename & " ---");
   begin
      Ada.Text_IO.Open (File => File_Handle, Mode => Ada.Text_IO.Append_File, Name => Filename);
      Ada.Text_IO.Put_Line (File_Handle, "--- Appended Content ---");
      Ada.Text_IO.Put_Line (File_Handle, "This line was appended.");
      Ada.Text_IO.Close (File_Handle);
      Ada.Text_IO.Put_Line ("Content appended successfully.");
   exception
      when Ada.Text_IO.Name_Error =>
         Ada.Text_IO.Put_Line ("Error: File not found for appending.");
   end;
end Write_File_Demo;

fileExists:
with Ada.Text_IO;
with Ada.Directories;

function File_Exists (Name : String) return Boolean is
   File : Ada.Text_IO.File_Type;
begin
   -- The canonical way to check for a file is to try to open it.
   -- This ensures it not only exists but is also a regular, readable file.
   Ada.Text_IO.Open (File => File, Mode => Ada.Text_IO.In_File, Name => Name);
   Ada.Text_IO.Close (File);
   return True;
exception
   when Ada.Text_IO.Name_Error | Ada.Text_IO.Status_Error =>
      return False;
end File_Exists;

procedure File_Exists_Demo is
   File_To_Check    : constant String := "output_ada.txt"; -- Should exist if writeFile ran
   Dir_To_Check     : constant String := "."; -- Current directory
   Non_Existent     : constant String := "no_such_file.ada";
begin
   Ada.Text_IO.Put_Line ("--- Checking for files and directories ---");

   -- Check for files
   Ada.Text_IO.Put ("'" & File_To_Check & "' (file)? ");
   Ada.Text_IO.Put_Line (Boolean'Image(File_Exists(File_To_Check)));

   Ada.Text_IO.Put ("'" & Non_Existent & "' (file)? ");
   Ada.Text_IO.Put_Line (Boolean'Image(File_Exists(Non_Existent)));

   -- Use Ada.Directories for checking directories
   Ada.Text_IO.Put ("'" & Dir_To_Check & "' (directory)? ");
   Ada.Text_IO.Put_Line (Boolean'Image(Ada.Directories.Exists(Dir_To_Check)));
end File_Exists_Demo;

dateTime:
with Ada.Text_IO;
with Ada.Calendar;

procedure Date_Time_Demo is
   -- Get the current time from the system clock
   Now : constant Ada.Calendar.Time := Ada.Calendar.Clock;

   -- Split the time into components
   Year    : Ada.Calendar.Year_Number;
   Month   : Ada.Calendar.Month_Number;
   Day     : Ada.Calendar.Day_Number;
   Seconds : Ada.Calendar.Day_Duration;
begin
   Ada.Calendar.Split (Date => Now, Year => Year, Month => Month, Day => Day, Seconds => Seconds);

   declare
      Hour   : Natural := Natural (Seconds) / 3600;
      Minute : Natural := (Natural (Seconds) mod 3600) / 60;
      Second : Natural := Natural (Seconds) mod 60;
   begin
      Ada.Text_IO.Put_Line ("--- Current Date and Time ---");
      Ada.Text_IO.Put_Line ("Year: " & Year'Image);
      Ada.Text_IO.Put_Line ("Month: " & Month'Image);
      Ada.Text_IO.Put_Line ("Day: " & Day'Image);
      Ada.Text_IO.Put_Line ("Hour: " & Hour'Image);
      Ada.Text_IO.Put_Line ("Minute: " & Minute'Image);
      Ada.Text_IO.Put_Line ("Second: " & Second'Image);

      -- Ada.Calendar.Image provides a standard string representation
      Ada.Text_IO.New_Line;
      Ada.Text_IO.Put_Line ("Formatted (Ada.Calendar.Image): " & Ada.Calendar.Image (Now));

      -- Epoch seconds are calculated relative to Ada's epoch (1900-01-01 00:00:00)
      -- or can be calculated relative to Unix epoch with an offset.
      declare
         Ada_Epoch : constant Ada.Calendar.Time := Ada.Calendar.Time_Of(1900, 1, 1);
         Seconds_Since_Ada_Epoch : constant Duration := Now - Ada_Epoch;
      begin
         Ada.Text_IO.New_Line;
         Ada.Text_IO.Put_Line ("Seconds Since Ada Epoch (1900-01-01): " & Duration'Image(Seconds_Since_Ada_Epoch));
      end;
   end;
end Date_Time_Demo;

maxInArray:
with Ada.Text_IO;

procedure Max_In_Array_Demo is
   -- Define a generic unconstrained array type
   type Integer_Array is array (Integer range <>) of Integer;

   function Max_Value (Arr : in Integer_Array) return Integer is
   begin
      -- This will raise Constraint_Error if the array is empty, which is idiomatic.
      declare
         Current_Max : Integer := Arr (Arr'First);
      begin
         for I in Arr'First + 1 .. Arr'Last loop
            if Arr (I) > Current_Max then
               Current_Max := Arr (I);
            end if;
         end loop;
         return Current_Max;
      end;
   end Max_Value;

   My_Numbers : constant Integer_Array := (10, 5, 42, 17, 8, 99, 32, -5, 0);
   Max        : Integer;
begin
   Ada.Text_IO.Put ("Array: ");
   for Elem of My_Numbers loop
      Ada.Text_IO.Put (Elem'Image & " ");
   end loop;
   Ada.Text_IO.New_Line;

   Max := Max_Value (My_Numbers);
   Ada.Text_IO.Put_Line ("Maximum value: " & Max'Image);
end Max_In_Array_Demo;
